#import "WBProductModel.h"
#import <YYKit/NSObject+YYModel.h>

@implementation WBProductModel

- (instancetype)init {
    self = [super init];
    if (self) {
        _serverPayMethods = [NSMutableArray array]; // 先初始化，否则会导致始终为空
    }
    return self;
}

- (CGFloat)discountedPrice {
    CGFloat originalPrice = [self.price floatValue];
    CGFloat discountedPrice = originalPrice - self.discountAmount;
    discountedPrice = discountedPrice > 0 ? discountedPrice : 0;
    discountedPrice = roundf(discountedPrice * 100) / 100;  // 四舍五入保留两位小数，防止浮点数的精度损失后显示异常

    for (NSDictionary *serverPaymethod in self.serverPayMethods) {
        if ([serverPaymethod[@"type"] isEqual:@(self.selectedPaymethod)]) {
            CGFloat discountValue = [serverPaymethod[@"discount"] doubleValue];
            discountedPrice = discountedPrice - discountValue;
            break;
        }
    }
    return discountedPrice;
}

- (CGFloat)discountAmount {
    if (![self.selectedPromoModels count]) return 0;
    CGFloat discountAmount = 0;
    for (WBPromoModel *promoModel in self.selectedPromoModels) {
        discountAmount += promoModel.discount;
    }
    return discountAmount;
}

/// Calcualted expire date combine both product and promo tickets' expire dates.
- (NSDate *)calculatedPromoExpireDate {
    NSDate *latestSelectedPromoTicketExpireDate = [self getLatestSelectedPromoTicketExpireDate];
    if (self.promoExpireDate) {
        return ([latestSelectedPromoTicketExpireDate compare:self.promoExpireDate] == NSOrderedAscending) ? latestSelectedPromoTicketExpireDate : self.promoExpireDate;
    } else {
        NSDateComponents *dateComps = [[NSCalendar currentCalendar] components:NSCalendarUnitDay fromDate:[NSDate date] toDate:latestSelectedPromoTicketExpireDate options:NSCalendarWrapComponents];
        return dateComps.day <= 2 ? latestSelectedPromoTicketExpireDate : nil;
    }
}

- (NSDate *)getLatestSelectedPromoTicketExpireDate {
    if (![self.selectedPromoModels count]) return nil;
    NSDate *res = nil;
    for (WBPromoModel *promo in self.selectedPromoModels) {
        if (!res || [promo.expireDate compare:res] == NSOrderedAscending) {
            res = promo.expireDate;
        }
    }
    return res;
}

#pragma mark - YYModel

+ (nullable NSArray<NSString *> *)modelPropertyBlacklist {
    return @[
        NSStringFromSelector(@selector(selected)),
        NSStringFromSelector(@selector(promoExpireDate)),
        NSStringFromSelector(@selector(calculatedPromoExpireDate)),
        NSStringFromSelector(@selector(selectedPromoModels)),
        NSStringFromSelector(@selector(discountedPrice)),
        NSStringFromSelector(@selector(discountAmount)),
        NSStringFromSelector(@selector(availablePromoCount)),
    ];
}

// 这里是从服务器请求来的json转appModel对象时的属性映射表
+ (NSDictionary *)modelCustomPropertyMapper {
    return @{
        NSStringFromSelector(@selector(productId)): @"id",
        NSStringFromSelector(@selector(desc)): @"description",
        NSStringFromSelector(@selector(promoExpireDate)): @"expires",
        NSStringFromSelector(@selector(payMethod)): @"mask",
    };
}

- (BOOL)modelCustomTransformFromDictionary:(NSDictionary *)dict {
    NSDateFormatter *dateFormatter = [NSDateFormatter wb_isoDateFormatter];
    NSString *kExpireDate = [[self class] modelCustomPropertyMapper][NSStringFromSelector(@selector(promoExpireDate))];
    NSString *expireDateStr = dict[kExpireDate];
    if ([expireDateStr isKindOfClass:[NSString class]] && expireDateStr.length) {
        self.promoExpireDate = [dateFormatter dateFromString:expireDateStr];
    }
    return true;
}

#pragma mark - mj extension compatibility

+ (NSArray *)mj_ignoredPropertyNames {
    return [self modelPropertyBlacklist];
}

+ (NSDictionary *)mj_replacedKeyFromPropertyName {
    return [self modelCustomPropertyMapper];
}

- (void)mj_didConvertToObjectWithKeyValues:(NSDictionary *)keyValues {
    [self modelCustomTransformFromDictionary:keyValues];
}

@end

