- (UIViewController *)findParentViewController {
    UIResponder *responder = self;
    while (responder) {
        if ([responder isKindOfClass:[UIViewController class]]) {
            return (UIViewController *)responder;
        }
        responder = [responder nextResponder];
    }
    return nil;
}

- (void)purchaseSelectedProduct {
    NSIndexPath *selectIndexPath = [self.productCollectionView indexPathsForSelectedItems].firstObject;
    WBProductModel *selectProduct = self.productCollectionView.products[selectIndexPath.row];

    [SVProgressHUD showWithStatus:@"正在充值会员"];

    if (self.payOptionsView.selectedPayMethod == WBPaymentMethodApplePay){
        if (selectProduct.discountAmount > 0) {
            self.couponCode = selectProduct.selectedPromoModels[0].code;
            UIAlertController *alertVc = [UIAlertController alertControllerWithTitle:@"温馨提示"
                                                                             message:@"\n「兑换」后支付，可享优惠\n继续支付将原价购买"
                                                                      preferredStyle:UIAlertControllerStyleAlert];
            UIAlertAction *redeemAction = [UIAlertAction actionWithTitle:@"兑换"
                                                                    style:UIAlertActionStyleDefault
                                                                  handler:^(UIAlertAction * _Nonnull action) {
                                                                      [self redeemButtonTapped];
                                                                  }];
            // 使用 KVC 修改“兑换”按钮的文字颜色为灰色
            [redeemAction setValue:RGB(102, 102, 102) forKey:@"titleTextColor"];
            UIAlertAction *payAction = [UIAlertAction actionWithTitle:@"继续支付"
                                                                 style:UIAlertActionStyleDefault
                                                               handler:^(UIAlertAction * _Nonnull action) {
                [[WBPaymentManager sharedManager] purchaseProduct:selectProduct pageSource:self.source payMethod:WBPaymentMethodApplePay];
                                                               }];
            [alertVc addAction:redeemAction];
            [alertVc addAction:payAction];
            dispatch_async(dispatch_get_main_queue(), ^{
                [self presentViewController:alertVc animated:YES completion:nil];
            });
        } else {
            [[WBPaymentManager sharedManager] purchaseProduct:selectProduct pageSource:self.source payMethod:WBPaymentMethodApplePay];
        }
    }
    else if (self.payOptionsView.selectedPayMethod == WBPaymentMethodAliPay){
        [[WBPaymentManager sharedManager] purchaseProduct:selectProduct pageSource:self.source payMethod:WBPaymentMethodAliPay];
    }
    else if (self.payOptionsView.selectedPayMethod == WBPaymentMethodWechatPay){
        [[WBPaymentManager sharedManager] purchaseProduct:selectProduct pageSource:self.source payMethod:WBPaymentMethodWechatPay];
    } else {
        [SVProgressHUD showErrorWithStatus:@"未知支付方式"];
    }
}

- (void)redeemButtonTapped {
    UIPasteboard *pasteboard = [UIPasteboard generalPasteboard];
    pasteboard.string = self.couponCode;
    if ([pasteboard.string isEqual:self.couponCode]) {
        [SVProgressHUD showSuccessWithStatus:@"兑换码已复制，请粘贴进行兑换，跳转界面中..."];
        [SVProgressHUD dismissWithDelay:1.5 completion:^{
            [WBPaymentManager.sharedManager presentCodeRedemptionSheet];
        }];
    } else {
        [SVProgressHUD showErrorWithStatus:@"兑换码复制失败，请点击重试"];
    }
}

