@implementation WBPaymentManager

#pragma mark - public

- (void)purchaseProduct:(WBProductModel *)product pageSource:(NSString *)pageSource payMethod:(WBPaymentMethod)payMethod {
    if (pageSource == nil) {
        pageSource = @"unknown";
    }
    self.isPaySuccessHasShown = NO;
    self.product = product;
    self.pageSource = pageSource;
    self.payMethod = payMethod;
    self.orderRefreshRetryCount = 0;
    self.isFromSinglePayPage = [pageSource isEqualToString:@"singlePayPage"];

    [self createOrderAndStartPaymentWithProduct:product payMethod:payMethod];
}

- (void)initGoods:(NSArray<WBProductModel *> *)goods {
    _goods = goods;
    NSMutableArray *goodsId = [NSMutableArray array];
    for (WBProductModel* good in goods) {
        [goodsId addObject:good.productId];
    }

    [[WBNetworkManager defaultManager] getPaymentMethodListByProductIds:goodsId callback:^(id  _Nullable json, NSError * _Nullable error) {

        for (NSDictionary *item in json) {
            NSArray *productIdList = item[@"productIdList"];
            NSMutableDictionary *method = [NSMutableDictionary dictionary];
            method[@"id"] = item[@"id"];
            method[@"type"] = item[@"type"];
            method[@"sort"] = item[@"sort"];
            method[@"discount"] = item[@"discount"];
            method[@"showBadge"] = item[@"showBadge"];
            method[@"badgeValue"] = item[@"badgeValue"];
            method[@"link"] = item[@"link"];

            for (NSNumber *productId in productIdList) {
                NSPredicate *predicate = [NSPredicate predicateWithFormat:@"productId == %@", productId];
                WBProductModel *product = [goods filteredArrayUsingPredicate:predicate].firstObject;
                if (product) {
                    [product.serverPayMethods addObject:method];
                }
            }
        }


    }];
