- (void)onAlipayClientSyncResult:(NSString *)result resultStatus:(NSString*)status {
    NSInteger statusCode = [status integerValue];
    switch(statusCode) {
        case 9000:
            // success
            self.orderRefreshRetryCount = 0;
            [self refreshOrderStatus:TRUE after:1];
            break;
        case 8000:
        case 6004:
            // might success
            [self refreshOrderStatus:TRUE after:1];
            break;
