    }
    self.isAliH5Paying = NO;
    self.isPaySuccessHasShown = YES;
}

#pragma mark - WECHATPAY callback

- (void)onResp:(BaseResp *)resp {
    if ([resp isKindOfClass:[PayResp class]]) {
        PayResp *payResp = (PayResp *)resp;
        switch (payResp.errCode) {
            case 0:
                NSLog(@"微信支付成功");
                // 支付成功
                self.orderRefreshRetryCount = 0;
                [self refreshOrderStatus:TRUE after:1];
                break;
            case -1:
                NSLog(@"微信支付失败");
                [self refreshOrderStatus:FALSE after:1];
                break;
            case -2:
                NSLog(@"微信支付取消");
                break;
            default:
                NSLog(@"未知错误: %ld", (long)payResp.errCode);
                if (self.isFromSinglePayPage) {
                    [self.vipUpgradeObserver onPaymentFailed:@"支付遇到问题"];
                } else {
                    [self.observer onPaymentFailed:@"支付遇到问题"];
                }
                break;
        }
    } else {
        NSLog(@"接收到非支付类型的响应: %@", resp);
    }
    self.isPaySuccessHasShown = YES;
}

#pragma mark - SYSTEM events

- (void)onAppBecomeActive {
    if (self.payMethod == WBPaymentMethodAliPay) {
        if (!self.isPaySuccessHasShown && !self.isAliH5Paying) {   // 如果正在支付过程中且不能是正在支付宝网页才进行
            [self checkOrderStatus];
        }
    } else if (self.payMethod == WBPaymentMethodWechatPay) {
        if (!self.isPaySuccessHasShown) {
            [self checkOrderStatus];
        }
    }
}

- (void)checkOrderStatus {
    [SVProgressHUD showWithStatus:@"正在充值会员"];
    self.isAppBecomeActiveToRefresh = YES;
    [self refreshOrderStatus:FALSE after:1];    // 支付完返回微盒就refresh一次，成功即可，若失败，则询问查询
    self.isPaySuccessHasShown = YES;    // 重置展示状态
}

- (void)dealloc {
    // 移除观察者
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}


